### Fastify Encapsulation with Nested Plugins and Routes (JavaScript)

Source: https://github.com/fastify/fastify/blob/main/docs/Reference/Encapsulation.md

This JavaScript code snippet demonstrates Fastify's encapsulation context. It registers decorators and plugins at different levels of nesting, defining routes that access these context-specific features. The example highlights how request decorators and plugins are scoped within their respective contexts.

```javascript
'use strict'

const fastify = require('fastify')()

fastify.decorateRequest('answer', 42)

fastify.register(async function authenticatedContext (childServer) {
  childServer.register(require('@fastify/bearer-auth'), { keys: ['abc123'] })

  childServer.route({
    path: '/one',
    method: 'GET',
    handler (request, response) {
      response.send({
        answer: request.answer,
        // request.foo will be undefined as it is only defined in publicContext
        foo: request.foo,
        // request.bar will be undefined as it is only defined in grandchildContext
        bar: request.bar
      })
    }
  })
})

fastify.register(async function publicContext (childServer) {
  childServer.decorateRequest('foo', 'foo')

  childServer.route({
    path: '/two',
    method: 'GET',
    handler (request, response) {
      response.send({
        answer: request.answer,
        foo: request.foo,
        // request.bar will be undefined as it is only defined in grandchildContext
        bar: request.bar
      })
    }
  })

  childServer.register(async function grandchildContext (grandchildServer) {
    grandchildServer.decorateRequest('bar', 'bar')

    grandchildServer.route({
      path: '/three',
      method: 'GET',
      handler (request, response) {
        response.send({
          answer: request.answer,
          foo: request.foo,
          bar: request.bar
        })
      }
    })
  })
})

fastify.listen({ port: 8000 })

```

--------------------------------

### Fastify Plugins: Extending Functionality and Encapsulation

Source: https://context7.com/fastify/fastify/llms.txt

Explains how to create and register Fastify plugins to extend functionality with routes, decorators, and hooks. Covers standard plugin encapsulation and using `fastify-plugin` for shared decorators without encapsulation.

```javascript
// Plugin definition
const myPlugin = async (fastify, options) => {
  // Add decorator available to this plugin and children
  fastify.decorate('utility', () => 'helper function')

  // Add request decorator
  fastify.decorateRequest('user', null)

  // Add reply decorator
  fastify.decorateReply('success', function(data) {
    return this.code(200).send({ success: true, data })
  })

  // Plugin routes inherit prefix
  fastify.get('/status', async (request, reply) => {
    return { status: 'ok', plugin: options.name }
  })
}

// Register plugin with prefix
fastify.register(myPlugin, {
  prefix: '/api/v1',
  name: 'myPlugin'
})

// Register versioned APIs
fastify.register(require('./routes/v1'), { prefix: '/v1' })
fastify.register(require('./routes/v2'), { prefix: '/v2' })

// Plugin with fastify-plugin for no encapsulation (shared decorators)
const fp = require('fastify-plugin')

const sharedPlugin = fp(async (fastify, options) => {
  fastify.decorate('db', await connectDatabase(options.connectionString))
}, {
  name: 'database-plugin',
  fastify: '5.x'
})

fastify.register(sharedPlugin, {
  connectionString: 'postgresql://localhost/mydb'
})
```

--------------------------------

### Encapsulated Hooks for Route-Specific Utilities

Source: https://github.com/fastify/fastify/blob/main/docs/Guides/Plugins-Guide.md

This snippet illustrates how to use Fastify's `register` function to encapsulate hooks, making them available only to a specific set of routes. This provides a way to conditionally apply utilities.

```javascript
fastify.register((instance, opts, done) => {
  instance.decorate('util', (request, key, value) => { request[key] = value })

  instance.addHook('preHandler', (request, reply, done) => {
    instance.util(request, 'timestamp', new Date())
    done()
  })

  instance.get('/plugin1', (request, reply) => {
    reply.send(request)
  })

  done()
})

fastify.get('/plugin2', (request, reply) => {
  reply.send(request)
})
```

