      secret: requireEnv('JWT_SECRET'),
      expiresIn: '24h',
    },
    encryption: {
      key: requireEnv('ENCRYPTION_KEY'),
    },
    rateLimit: {
      bookingPerUser: 20,
      bookingPerOrg: 200,
    },
    credit: {
      threshold: 20,
    },
  };
}
"}

