{"file_path": "E:\Hale\Coding\Eaglepoint\Task-54\repo\backend\src\api\server.ts", "content": "import Fastify, { FastifyInstance } from 'fastify';
import cors from '@fastify/cors';
import { logger } from '../infrastructure/logging/index.js';

export async function buildServer(): Promise<FastifyInstance> {
  const app = Fastify({
    logger: false,
    trustProxy: true,
  });

  // CORS — LAN only
  await app.register(cors, {
    origin: true,
    credentials: true,
  });

  // Global error handler
  app.setErrorHandler((error, request, reply) => {
    const statusCode = error.statusCode ?? 500;

    if (statusCode >= 500) {
      logger.error({
        err: error.message,
        stack: error.stack,
        method: request.method,
        url: request.url,
        userId: (request as any).userId,
      }, 'Internal server error');
    }

    const response: Record<string, unknown> = {
      error: getErrorCode(statusCode),
      message: statusCode >= 500 ? 'An unexpected error occurred' : error.message,
    };

    if ((error as any).details) {
      response.details = (error as any).details;
    }

    if ((error as any).retryAfterSeconds) {
      response.retryAfterSeconds = (error as any).retryAfterSeconds;
    }

    reply.status(statusCode).send(response);
  });

  // Health check
  app.get('/api/health', async () => {
    return { status: 'ok', timestamp: new Date().toISOString() };
  });

  // Time sync endpoint (public)
  app.get('/api/time', async () => {
    return { serverTime: new Date().toISOString() };
  });

  return app;
}

function getErrorCode(statusCode: number): string {
  const codes: Record<number, string> = {
    400: 'BAD_REQUEST',
    401: 'UNAUTHORIZED',
    403: 'FORBIDDEN',
    404: 'NOT_FOUND',
    409: 'CONFLICT',
    422: 'VALIDATION_ERROR',
    423: 'LOCKED',
    429: 'RATE_LIMITED',
    500: 'INTERNAL_ERROR',
    503: 'SERVICE_UNAVAILABLE',
  };
  return codes[statusCode] ?? 'UNKNOWN_ERROR';
}
"}

