{"file_path": "E:\Hale\Coding\Eaglepoint\Task-54\repo\backend\src\api\plugins\jwt-auth.plugin.ts", "content": "import fp from 'fastify-plugin';
import jwt from '@fastify/jwt';
import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { KnexSessionRepository } from '../../infrastructure/database/repositories/session-repository.js';
import { getKnex } from '../../infrastructure/database/connection.js';
import { logger } from '../../infrastructure/logging/index.js';

declare module 'fastify' {
  interface FastifyInstance {
    authenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
  }
}

declare module '@fastify/jwt' {
  interface FastifyJWT {
    payload: {
      userId: string;
      orgId: string;
      role: string;
      nonce: string;
      jti: string;
    };
    user: {
      userId: string;
      orgId: string;
      role: string;
      nonce: string;
      jti: string;
    };
  }
}

export default fp(async (app: FastifyInstance) => {
  const secret = process.env.JWT_SECRET || 'dev-jwt-secret-change-in-production-min32chars';

  await app.register(jwt, {
    secret,
    sign: { expiresIn: '24h' },
  });

  app.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();

      // Validate session nonce
      const { userId, nonce } = request.user;
      const db = getKnex();
      const sessionRepo = new KnexSessionRepository(db);
      const session = await sessionRepo.findByUserIdAndNonce(userId, nonce);

      if (!session) {
        logger.warn({ userId }, 'Session nonce invalid — session revoked by new login');
        reply.status(401).send({
          error: 'UNAUTHORIZED',
          message: 'Session expired or revoked. Please log in again.',
        });
        return;
      }
    } catch (err) {
      reply.status(401).send({
        error: 'UNAUTHORIZED',
        message: 'Invalid or expired token',
      });
    }
  });
}, { name: 'jwt-auth' });
"}

