import { FastifyInstance, FastifyRequest } from 'fastify';
import { getKnex } from '../../infrastructure/database/connection.js';

export default fp(async (app: FastifyInstance) => {
  app.addHook('preHandler', async (request: FastifyRequest) => {
    if (!request.user) return;

    const db = getKnex();
    const { orgId, role, userId } = request.user;

    // Super admin bypasses RLS
    if (role === 'super_admin') {
      await db.raw("SET LOCAL app.current_org_id = ''");
    } else {
      await db.raw('SET LOCAL app.current_org_id = ?', [orgId]);
    }
    await db.raw('SET LOCAL app.current_role = ?', [role]);
    await db.raw('SET LOCAL app.current_user_id = ?', [userId]);
    await db.raw("SET LOCAL app.bypass_rls = 'false'");
  });
}, { name: 'org-isolation' });
"}

