5	export async function buildServer(): Promise<FastifyInstance> {
6	  const app = Fastify({
7	    logger: false,
8	    trustProxy: true,
9	  });
10	
11	  // CORS — LAN only
12	  await app.register(cors, {
13	    origin: true,
14	    credentials: true,
15	  });
16	
17	  // Global error handler
18	  app.setErrorHandler((error, request, reply) => {
19	    const statusCode = error.statusCode ?? 500;
20	
21	    if (statusCode >= 500) {
22	      logger.error({
23	        err: error.message,
24	        stack: error.stack,
25	        method: request.method,
26	        url: request.url,
27	        userId: (request as any).userId,
28	      }, 'Internal server error');
29	    }
30	
31	    const response: Record<string, unknown> = {
32	      error: getErrorCode(statusCode),
33	      message: statusCode >= 500 ? 'An unexpected error occurred' : error.message,
34	    };
35	
36	    if ((error as any).details) {
37	      response.details = (error as any).details;
38	    }
39	
40	    if ((error as any).retryAfterSeconds) {
41	      response.retryAfterSeconds = (error as any).retryAfterSeconds;
42	    }
43	
44	    reply.status(statusCode).send(response);
45	  });
46	
47	  // Health check
48	  app.get('/api/health', async () => {
49	    return { status: 'ok', timestamp: new Date().toISOString() };
50	  });
51	
52	  // Time sync endpoint (public)
53	  app.get('/api/time', async () => {
54	    return { serverTime: new Date().toISOString() };
55	  });
56	
57	  return app;
58	}
59	
60	function getErrorCode(statusCode: number): string {
61	  const codes: Record<number, string> = {
62	    400: 'BAD_REQUEST',
63	    401: 'UNAUTHORIZED',
64	    403: 'FORBIDDEN',
65	    404: 'NOT_FOUND',
66	    409: 'CONFLICT',
67	    422: 'VALIDATION_ERROR',
68	    423: 'LOCKED',
69	    429: 'RATE_LIMITED',
70	    500: 'INTERNAL_ERROR',
71	    503: 'SERVICE_UNAVAILABLE',
72	  };
73	  return codes[statusCode] ?? 'UNKNOWN_ERROR';
74	}
