7	export async function buildServer(): Promise<FastifyInstance> {
8	  const app = Fastify({
9	    logger: false,
10	    trustProxy: true,
11	  });
12	
13	  // CORS — LAN only
14	  await app.register(cors, {
15	    origin: true,
16	    credentials: true,
17	  });
18	
19	  // JWT Auth plugin
20	  await app.register(jwtAuthPlugin);
21	
22	  // Routes
23	  await app.register(authRoutes);
24	
25	  // Global error handler
26	  app.setErrorHandler((error, request, reply) => {
27	    const statusCode = error.statusCode ?? 500;
28	
29	    if (statusCode >= 500) {
30	      logger.error({
31	        err: error.message,
32	        stack: error.stack,
33	        method: request.method,
34	        url: request.url,
35	        userId: (request as any).userId,
36	      }, 'Internal server error');
37	    }
38	
39	    const response: Record<string, unknown> = {
40	      error: getErrorCode(statusCode),
41	      message: statusCode >= 500 ? 'An unexpected error occurred' : error.message,
42	    };
43	
44	    if ((error as any).details) {
45	      response.details = (error as any).details;
46	    }
47	
48	    if ((error as any).retryAfterSeconds) {
49	      response.retryAfterSeconds = (error as any).retryAfterSeconds;
50	    }
51	
52	    reply.status(statusCode).send(response);
53	  });
54	
55	  // Health check
56	  app.get('/api/health', async () => {
57	    return { status: 'ok', timestamp: new Date().toISOString() };
58	  });
59	
60	  // Time sync endpoint (public)
61	  app.get('/api/time', async () => {
62	    return { serverTime: new Date().toISOString() };
63	  });
64	
65	  return app;
66	}
67	
68	function getErrorCode(statusCode: number): string {
69	  const codes: Record<number, string> = {
70	    400: 'BAD_REQUEST',
71	    401: 'UNAUTHORIZED',
72	    403: 'FORBIDDEN',
73	    404: 'NOT_FOUND',
74	    409: 'CONFLICT',
75	    422: 'VALIDATION_ERROR',
76	    423: 'LOCKED',
77	    429: 'RATE_LIMITED',
78	    500: 'INTERNAL_ERROR',
79	    503: 'SERVICE_UNAVAILABLE',
80	  };
81	  return codes[statusCode] ?? 'UNKNOWN_ERROR';
