1	import { buildServer } from './api/server.js';
2	import { initDatabase, closeDatabase } from './infrastructure/database/connection.js';
3	import { loadConfig } from './config/index.js';
4	import { logger } from './infrastructure/logging/index.js';
5	
6	async function main() {
7	  const config = loadConfig();
8	
9	  logger.info({ nodeEnv: config.nodeEnv }, 'Starting JusticeOps backend');
10	
11	  // Initialize database
12	  const db = await initDatabase(config.database.url);
13	
14	  // Run migrations
15	  logger.info('Running database migrations...');
16	  await db.migrate.latest();
17	  logger.info('Migrations complete');
18	
19	  // Run seeds in non-production or if DB is empty
20	  const userCount = await db('users').count('id as count').first();
21	  if (!userCount || Number(userCount.count) === 0) {
22	    logger.info('Running database seeds...');
23	    await db.seed.run();
24	    logger.info('Seeds complete');
25	  }
26	
27	  // Build and start server
28	  const app = await buildServer();
29	
30	  // Store config and db on app for plugins to use
31	  app.decorate('config', config);
32	  app.decorate('db', db);
33	
34	  try {
35	    await app.listen({ port: config.port, host: '0.0.0.0' });
36	    logger.info({ port: config.port }, 'JusticeOps backend running');
37	  } catch (err) {
38	    logger.error({ err }, 'Failed to start server');
39	    await closeDatabase();
40	    process.exit(1);
41	  }
42	
43	  // Graceful shutdown
44	  const shutdown = async () => {
45	    logger.info('Shutting down...');
46	    await app.close();
47	    await closeDatabase();
48	    process.exit(0);
49	  };
50	
51	  process.on('SIGINT', shutdown);
52	  process.on('SIGTERM', shutdown);
53	}
54	
55	main().catch((err) => {
56	  logger.error({ err }, 'Fatal error during startup');
57	  process.exit(1);
58	});
