:root {
  --color-primary: #2563eb;
  --color-primary-hover: #1d4ed8;
  --color-primary-light: #dbeafe;
  --color-secondary: #64748b;
  --color-success: #16a34a;
  --color-warning: #d97706;
  --color-danger: #dc2626;
  --color-danger-hover: #b91c1c;
  --color-surface: #ffffff;
  --color-surface-secondary: #f8fafc;
  --color-sidebar: #1e293b;
  --color-sidebar-text: #e2e8f0;
  --color-sidebar-hover: #334155;
  --color-border: #e2e8f0;
  --color-text: #0f172a;
  --color-text-secondary: #64748b;
  --color-text-muted: #94a3b8;

  --spacing-xs: 4px;
  --spacing-sm: 8px;
  --spacing-md: 16px;
  --spacing-lg: 24px;
  --spacing-xl: 32px;
  --spacing-2xl: 48px;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;

  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  color: var(--color-text);
  background: var(--color-surface-secondary);
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
}

h1 { font-size: 1.875rem; font-weight: 700; line-height: 2.25rem; }
h2 { font-size: 1.5rem; font-weight: 600; line-height: 2rem; }
h3 { font-size: 1.25rem; font-weight: 600; line-height: 1.75rem; }
h4 { font-size: 1.125rem; font-weight: 500; line-height: 1.5rem; }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  border-radius: var(--radius-md);
  font-weight: 500;
  font-size: 0.875rem;
  cursor: pointer;
  border: 1px solid transparent;
  transition: all 0.15s ease;

  &:focus-visible {
    outline: 2px solid var(--color-primary);
    outline-offset: 2px;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.btn-primary {
  background: var(--color-primary);
  color: white;
  &:hover:not(:disabled) { background: var(--color-primary-hover); }
  &:active:not(:disabled) { transform: scale(0.98); }
}

.btn-secondary {
  background: var(--color-surface);
  color: var(--color-text);
  border-color: var(--color-border);
  &:hover:not(:disabled) { background: var(--color-surface-secondary); }
}

.btn-danger {
  background: var(--color-danger);
  color: white;
  &:hover:not(:disabled) { background: var(--color-danger-hover); }
}

.card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--spacing-lg);
  box-shadow: var(--shadow-sm);
}

.input {
  width: 100%;
  padding: var(--spacing-sm) var(--spacing-md);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 0.875rem;
  transition: border-color 0.15s ease;

  &:focus {
    outline: none;
    border-color: var(--color-primary);
    box-shadow: 0 0 0 3px var(--color-primary-light);
  }

  &:disabled {
    background: var(--color-surface-secondary);
    cursor: not-allowed;
  }
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 2px var(--spacing-sm);
  border-radius: 9999px;
  font-size: 0.75rem;
  font-weight: 500;

  &.badge-success { background: #dcfce7; color: #166534; }
  &.badge-warning { background: #fef3c7; color: #92400e; }
  &.badge-danger { background: #fee2e2; color: #991b1b; }
  &.badge-info { background: #dbeafe; color: #1e40af; }
  &.badge-neutral { background: #f1f5f9; color: #475569; }
}

.shimmer {
  background: linear-gradient(90deg, #f1f5f9 25%, #e2e8f0 50%, #f1f5f9 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
  border-radius: var(--radius-md);
}

@keyframes shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.policy-banner {
  background: #fef3c7;
  border: 1px solid #fbbf24;
  border-radius: var(--radius-md);
  padding: var(--spacing-sm) var(--spacing-md);
  font-size: 0.875rem;
  color: #92400e;
}

.permission-feedback {
  background: #fee2e2;
  border: 1px solid #fecaca;
  border-radius: var(--radius-md);
  padding: var(--spacing-sm) var(--spacing-md);
  font-size: 0.875rem;
  color: #991b1b;
}

.table {
  width: 100%;
  border-collapse: collapse;

  th, td {
    padding: var(--spacing-sm) var(--spacing-md);
    text-align: left;
    border-bottom: 1px solid var(--color-border);
    font-size: 0.875rem;
  }

  th {
    font-weight: 600;
    color: var(--color-text-secondary);
    background: var(--color-surface-secondary);
  }

  tr:hover td {
    background: var(--color-surface-secondary);
  }
}
"}

