  private pollInterval: any;

  constructor(private http: HttpClient) {}

  startPolling() {
    this.fetch();
    this.pollInterval = setInterval(() => this.fetch(), 30000); // every 30s
  }

  stopPolling() {
    if (this.pollInterval) clearInterval(this.pollInterval);
  }

  fetch() {
