      next: (res) => {
        this.notifications.set(res.data);
        this.unreadCount.set(res.unreadCount);
      },
    });
  }

  markRead(id: string) {
    this.http.patch<any>(`/api/notifications/${id}/read`, {}).subscribe({
      next: () => this.fetch(),
    });
  }

  markAllRead() {
    this.http.patch('/api/notifications/read-all', {}).subscribe({
      next: () => this.fetch(),
    });
  }
}
"}

