110	export class LoginComponent implements OnInit, OnDestroy {
111	  username = '';
112	  password = '';
113	  loading = false;
114	  errorMessage = '';
115	  sessionMessage = '';
116	  lockoutSeconds = 0;
117	  private lockoutTimer: any;
118	
119	  constructor(
120	    private auth: AuthService,
121	    private router: Router,
122	    private route: ActivatedRoute
123	  ) {}
124	
125	  ngOnInit() {
126	    if (this.auth.isLoggedIn()) {
127	      this.router.navigate([this.auth.getDefaultRoute()]);
128	      return;
129	    }
130	    this.route.queryParams.subscribe(params => {
131	      if (params['message']) {
132	        this.sessionMessage = params['message'];
133	      }
134	    });
135	  }
136	
137	  ngOnDestroy() {
138	    if (this.lockoutTimer) clearInterval(this.lockoutTimer);
139	  }
140	
141	  onSubmit() {
142	    this.errorMessage = '';
143	    this.sessionMessage = '';
144	    this.loading = true;
145	
146	    this.auth.login(this.username, this.password).subscribe({
147	      next: (response) => {
148	        this.auth.handleLoginSuccess(response);
149	        this.loading = false;
150	        this.router.navigate([this.auth.getDefaultRoute()]);
151	      },
152	      error: (err: HttpErrorResponse) => {
153	        this.loading = false;
154	        if (err.status === 423) {
155	          const retryAfter = err.error?.retryAfterSeconds ?? 60;
156	          this.startLockout(retryAfter);
157	        } else if (err.status === 401) {
158	          this.errorMessage = 'Invalid username or password.';
159	        } else {
160	          this.errorMessage = err.error?.message ?? 'Login failed. Please try again.';
161	        }
162	      },
163	    });
164	  }
165	
166	  private startLockout(seconds: number) {
167	    this.lockoutSeconds = seconds;
168	    this.lockoutTimer = setInterval(() => {
169	      this.lockoutSeconds--;
170	      if (this.lockoutSeconds <= 0) {
171	        clearInterval(this.lockoutTimer);
172	      }
173	    }, 1000);
174	  }
175	}
