import { login, waitForShell, getAuthToken } from './helpers';

test.describe('Client Bookings', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/login');
    await page.evaluate(() => localStorage.clear());
    await login(page, 'client1');
    await waitForShell(page);
  });

  test('booking list page loads', async ({ page }) => {
    await page.goto('/client/bookings');
    await expect(page.locator('h2')).toContainText('Bookings');
  });

  test('booking create page loads with form fields', async ({ page }) => {
    await page.goto('/client/bookings/create');
    await expect(page.locator('h2')).toContainText('New Booking');
    // Should have a type selector and a lawyer dropdown
    await expect(page.locator('select').first()).toBeVisible();
  });

  test('credit history page loads and shows score', async ({ page }) => {
    await page.goto('/client/credit-history');
    await expect(page.locator('h2')).toContainText('Credit');
    // Score should be displayed
    await expect(page.locator('.credit-number, .score-value, h2').first()).toBeVisible();
  });
});

test.describe('Client Booking API Flow', () => {
  test('creates and lists a consultation booking via API', async ({ page }) => {
    const token = await getAuthToken(page, 'client1');

    // Get lawyer list to find a valid lawyerId
    const usersRes = await page.request.get('/api/users?role=lawyer', {
      headers: { Authorization: `Bearer ${token}` },
    });
    // If this fails (client can't list users), use a known seed username
    let lawyerId: string;
    if (usersRes.ok()) {
      const users = await usersRes.json();
      lawyerId = users.data[0].id;
    } else {
      // Get it via /api/auth/me for the lawyer
      const lawyerToken = await getAuthToken(page, 'lawyer1');
      const meRes = await page.request.get('/api/auth/me', {
        headers: { Authorization: `Bearer ${lawyerToken}` },
      });
      const meBody = await meRes.json();
      lawyerId = meBody.user.id;
    }

    // Create a consultation booking
    const tomorrow = new Date(Date.now() + 86400000);
    tomorrow.setHours(10, 0, 0, 0);
    const idempotencyKey = crypto.randomUUID();

    const createRes = await page.request.post('/api/bookings', {
      headers: { Authorization: `Bearer ${token}` },
      data: {
        lawyerId,
        type: 'consultation',
        scheduledAt: tomorrow.toISOString(),
        idempotencyKey,
      },
    });
    expect(createRes.status()).toBe(201);
    const { booking } = await createRes.json();
    expect(booking.status).toBe('pending');
    expect(booking.type).toBe('consultation');

    // Verify idempotency — same key should return same response
    const dupRes = await page.request.post('/api/bookings', {
      headers: { Authorization: `Bearer ${token}` },
      data: {
        lawyerId,
        type: 'consultation',
        scheduledAt: tomorrow.toISOString(),
        idempotencyKey,
      },
    });
    expect(dupRes.status()).toBe(201);
    const dupBody = await dupRes.json();
    expect(dupBody.booking.id).toBe(booking.id);

    // List bookings and verify it appears
    const listRes = await page.request.get('/api/bookings', {
      headers: { Authorization: `Bearer ${token}` },
    });
    expect(listRes.ok()).toBe(true);
    const listBody = await listRes.json();
    expect(listBody.data.length).toBeGreaterThan(0);
    expect(listBody.data.some((b: any) => b.id === booking.id)).toBe(true);
  });
});
"}

