1	import pino from 'pino';
2	
3	const PII_PATTERNS = [
4	  { pattern: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, replacement: '[EMAIL_REDACTED]' },
5	  { pattern: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, replacement: '[PHONE_REDACTED]' },
6	  { pattern: /\b\d{3}-\d{2}-\d{4}\b/g, replacement: '[SSN_REDACTED]' },
7	  { pattern: /"password"\s*:\s*"[^"]*"/gi, replacement: '"password":"[REDACTED]"' },
8	  { pattern: /"token"\s*:\s*"[^"]*"/gi, replacement: '"token":"[REDACTED]"' },
9	  { pattern: /"sessionNonce"\s*:\s*"[^"]*"/gi, replacement: '"sessionNonce":"[REDACTED]"' },
10	  { pattern: /"authorization"\s*:\s*"[^"]*"/gi, replacement: '"authorization":"[REDACTED]"' },
11	];
12	
13	function maskPII(input: string): string {
14	  let masked = input;
15	  for (const { pattern, replacement } of PII_PATTERNS) {
16	    masked = masked.replace(pattern, replacement);
17	  }
18	  return masked;
19	}
20	
21	export function createLogger(name: string) {
22	  const isProduction = process.env.NODE_ENV === 'production';
23	  const isTest = process.env.NODE_ENV === 'test';
24	
25	  return pino({
26	    name,
27	    level: isTest ? 'silent' : (isProduction ? 'info' : 'debug'),
28	    formatters: {
29	      log(object: Record<string, unknown>) {
30	        const masked: Record<string, unknown> = {};
31	        for (const [key, value] of Object.entries(object)) {
32	          if (typeof value === 'string') {
33	            masked[key] = maskPII(value);
34	          } else if (typeof value === 'object' && value !== null) {
35	            masked[key] = JSON.parse(maskPII(JSON.stringify(value)));
36	          } else {
37	            masked[key] = value;
38	          }
39	        }
40	        return masked;
41	      },
42	    },
43	    transport: isProduction
44	      ? undefined
45	      : { target: 'pino-pretty', options: { colorize: true } },
46	  });
47	}
48	
49	export const logger = createLogger('justiceops');
