const net = require('net');
const sock = net.createConnection(5433, '127.0.0.1', () => {
  console.log('TCP connected');
  const user = 'justiceops';
  const db = 'justiceops';
  const buf = Buffer.alloc(1024);
  let offset = 4;
  buf.writeInt32BE(196608, offset); offset += 4;
  offset += buf.write('user\0', offset);
  offset += buf.write(user + '\0', offset);
  offset += buf.write('database\0', offset);
  offset += buf.write(db + '\0', offset);
  buf[offset++] = 0;
  buf.writeInt32BE(offset, 0);
  sock.write(buf.subarray(0, offset));
});
sock.on('data', (data) => {
  const msgType = String.fromCharCode(data[0]);
  const len = data.readInt32BE(1);
  if (msgType === 'R') {
    const authType = data.readInt32BE(5);
    console.log('Auth type:', authType);
    // 0 = OK, 3 = cleartext, 5 = MD5, 10 = SASL
    if (authType === 0) console.log('AUTH OK (trust)');
    else if (authType === 10) console.log('AUTH SASL - NOT trust!');
    else console.log('Other auth type');
  } else {
    console.log('Msg:', msgType);
  }
  sock.destroy();
});
sock.on('error', (e) => console.error('err:', e.message));
setTimeout(() => process.exit(0), 3000);
" 2>&1", "description": "Raw protocol auth check", "timeout": 10000}

