### 4. Rate-Limit Plugin

**Full `consumeToken` function (lines 11-41):**
```typescript
async function consumeToken(bucketId: string, maxTokens: number, refillRate: number): Promise<{ allowed: boolean; retryAfterSeconds: number }> {
  const db = getKnex();
  const now = new Date();

  // Upsert bucket
  await db.raw(`
    INSERT INTO rate_limit_buckets (id, tokens, max_tokens, refill_rate, last_refill_at)
    VALUES (?, ?, ?, ?, ?)
    ON CONFLICT (id) DO NOTHING
  `, [bucketId, maxTokens, maxTokens, refillRate, now]);

  // Atomic refill + consume
  const result = await db.raw(`
    UPDATE rate_limit_buckets
    SET
      tokens = GREATEST(0, LEAST(
        max_tokens,
        tokens + refill_rate * EXTRACT(EPOCH FROM (NOW() - last_refill_at))
      ) - 1),
      last_refill_at = NOW()
    WHERE id = ?
    RETURNING tokens
  `, [bucketId]);

  const remaining = result.rows[0]?.tokens ?? 0;
  if (remaining < 0) {
    const retryAfter = Math.ceil(1 / refillRate);
    return { allowed: false, retryAfterSeconds: retryAfter };
  }
  return { allowed: true, retryAfterSeconds: 0 };
}
```

**Full `rateLimitBooking` function (lines 43-67):**
```typescript
export async function rateLimitBooking(request: FastifyRequest, reply: FastifyReply) {
  if (!request.user) return;

  const { userId, orgId } = request.user;

  // Per-user limit: 20/min = 0.333/sec
  const userResult = await consumeToken(`user:${userId}`, 20, 20 / 60);
  if (!userResult.allowed) {
    return reply.status(429).send({
      error: 'RATE_LIMITED',
      message: 'Too many requests. Please try again later.',
      retryAfterSeconds: userResult.retryAfterSeconds,
    });
  }

  // Per-org limit: 200/min = 3.333/sec
  const orgResult = await consumeToken(`org:${orgId}`, 200, 200 / 60);
  if (!orgResult.allowed) {
    return reply.status(429).send({
      error: 'RATE_LIMITED',
      message: 'Organization rate limit exceeded. Please try again later.',
      retryAfterSeconds: orgResult.retryAfterSeconds,
    });
  }
}
```

