11	  standalone: true,
12	  imports: [CommonModule, FormsModule, ShimmerLoaderComponent],
13	  template: `
14	    <div class="page">
15	      <h2>Booking Requests</h2>
16	
17	      <div class="filters">
18	        <select class="input filter-select" [(ngModel)]="statusFilter" (ngModelChange)="loadBookings()">
19	          <option value="">All Statuses</option>
20	          <option value="pending">Pending</option>
21	          <option value="confirmed">Confirmed</option>
22	          <option value="completed">Completed</option>
23	          <option value="cancelled">Cancelled</option>
24	          <option value="no_show">No Show</option>
25	        </select>
26	      </div>
27	
28	      @if (loading) {
29	        <app-shimmer-loader [lines]="6" />
30	      } @else {
31	        <div class="card table-card">
32	          <table class="table">
33	            <thead>
34	              <tr>
35	                <th>Client</th>
36	                <th>Credit</th>
37	                <th>Type</th>
38	                <th>Status</th>
39	                <th>Scheduled</th>
40	                <th>Actions</th>
41	              </tr>
42	            </thead>
43	            <tbody>
44	              @for (booking of bookings; track booking.id) {
45	                <tr>
46	                  <td>{{ booking.clientId }}</td>
47	                  <td>
48	                    <span class="badge" [ngClass]="getCreditClass(clientCredits[booking.clientId])">
49	                      {{ clientCredits[booking.clientId] ?? '...' }}
50	                    </span>
51	                  </td>
52	                  <td>{{ booking.type }}</td>
53	                  <td>
54	                    <span class="badge" [ngClass]="getStatusClass(booking.status)">{{ booking.status }}</span>
55	                  </td>
56	                  <td>{{ (booking.scheduledAt || booking.deadlineAt) | date:'medium' }}</td>
57	                  <td class="actions">
58	                    @if (booking.status === 'pending') {
59	                      <button class="btn btn-primary" (click)="updateStatus(booking.id, 'confirmed')">Accept</button>
60	                      <button class="btn btn-danger" (click)="updateStatus(booking.id, 'declined')">Decline</button>
61	                    }
62	                    @if (booking.status === 'confirmed') {
63	                      <button class="btn btn-primary" (click)="updateStatus(booking.id, 'completed')">Complete</button>
64	                      <button class="btn btn-danger" (click)="updateStatus(booking.id, 'no_show')">No-show</button>
65	                    }
66	                  </td>
67	                </tr>
68	              }
69	              @if (bookings.length === 0) {
70	                <tr><td colspan="6" class="empty-text">No bookings found.</td></tr>
71	              }
72	            </tbody>
73	          </table>
74	        </div>
75	      }
76	    </div>
77	  `,
78	  styles: [`
79	    .page h2 { margin-bottom: var(--spacing-md); }
80	    .filters { margin-bottom: var(--spacing-md); }
81	    .filter-select { max-width: 200px; }
82	    .table-card { padding: 0; overflow-x: auto; }
83	    .actions { display: flex; gap: var(--spacing-xs); }
84	    .empty-text { text-align: center; color: var(--color-text-muted); padding: var(--spacing-lg); }
85	  `]
86	})
87	export class BookingRequestsComponent implements OnInit {
88	  bookings: Booking[] = [];
89	  loading = true;
90	  statusFilter = '';
91	  clientCredits: Record<string, number> = {};
92	
93	  constructor(private http: HttpClient, private auth: AuthService) {}
94	
95	  ngOnInit() {
96	    this.loadBookings();
97	  }
98	
99	  loadBookings() {
100	    this.loading = true;
101	    const userId = this.auth.currentUser()?.id;
102	    let url = `/api/bookings?lawyerId=${userId}`;
103	    if (this.statusFilter) url += `&status=${this.statusFilter}`;
104	
105	    this.http.get<{ data: Booking[] }>(url).subscribe({
106	      next: (res) => {
107	        this.bookings = res.data;
108	        this.loading = false;
109	        // Load client credit scores
110	        const clientIds = [...new Set(res.data.map(b => b.clientId))];
111	        clientIds.forEach(cid => {
112	          this.http.get<{ creditScore: number }>(`/api/credit/${cid}`).subscribe({
113	            next: (r) => (this.clientCredits[cid] = r.creditScore),
114	          });
115	        });
116	      },
117	      error: () => (this.loading = false),
118	    });
119	  }
120	
121	  updateStatus(bookingId: string, status: string) {
122	    this.http.patch(`/api/bookings/${bookingId}/status`, { status }).subscribe({
123	      next: () => this.loadBookings(),
124	    });
125	  }
126	
127	  getStatusClass(status: string): string {
128	    const map: Record<string, string> = {
129	      pending: 'badge-warning', confirmed: 'badge-info', completed: 'badge-success',
130	      cancelled: 'badge-neutral', no_show: 'badge-danger', declined: 'badge-danger',
131	    };
132	    return map[status] ?? 'badge-neutral';
133	  }
134	
135	  getCreditClass(score: number | undefined): string {
136	    if (score === undefined) return 'badge-neutral';
137	    if (score > 60) return 'badge-success';
138	    if (score >= 20) return 'badge-warning';
139	    return 'badge-danger';
140	  }
141	}
