import { Router, ActivatedRouteSnapshot, RouterStateSnapshot } from '@angular/router';
import { authGuard, roleGuard } from './auth.guard';
import { AuthService } from '../services/auth.service';

describe('Auth Guards', () => {
  let authServiceSpy: jasmine.SpyObj<AuthService>;
  let routerSpy: jasmine.SpyObj<Router>;

  beforeEach(() => {
    authServiceSpy = jasmine.createSpyObj('AuthService', ['isLoggedIn', 'userRole', 'getDefaultRoute']);
    routerSpy = jasmine.createSpyObj('Router', ['navigate']);

    TestBed.configureTestingModule({
      providers: [
        { provide: AuthService, useValue: authServiceSpy },
        { provide: Router, useValue: routerSpy },
      ],
    });
  });

  describe('authGuard', () => {
    it('should return true when user is logged in', () => {
      authServiceSpy.isLoggedIn.and.returnValue(true);
      const result = TestBed.runInInjectionContext(() =>
        authGuard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeTrue();
    });

    it('should navigate to /login and return false when not logged in', () => {
      authServiceSpy.isLoggedIn.and.returnValue(false);
      const result = TestBed.runInInjectionContext(() =>
        authGuard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeFalse();
      expect(routerSpy.navigate).toHaveBeenCalledWith(['/login']);
    });
  });

  describe('roleGuard', () => {
    it('should return true when user has allowed role', () => {
      authServiceSpy.isLoggedIn.and.returnValue(true);
      authServiceSpy.userRole.and.returnValue('client');
      const guard = roleGuard('client');
      const result = TestBed.runInInjectionContext(() =>
        guard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeTrue();
    });

    it('should redirect when user has wrong role', () => {
      authServiceSpy.isLoggedIn.and.returnValue(true);
      authServiceSpy.userRole.and.returnValue('client');
      authServiceSpy.getDefaultRoute.and.returnValue('/client/dashboard');
      const guard = roleGuard('admin');
      const result = TestBed.runInInjectionContext(() =>
        guard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeFalse();
      expect(routerSpy.navigate).toHaveBeenCalledWith(['/client/dashboard']);
    });

    it('should accept multiple roles', () => {
      authServiceSpy.isLoggedIn.and.returnValue(true);
      authServiceSpy.userRole.and.returnValue('super_admin');
      const guard = roleGuard('admin', 'super_admin');
      const result = TestBed.runInInjectionContext(() =>
        guard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeTrue();
    });

    it('should redirect to login when not logged in', () => {
      authServiceSpy.isLoggedIn.and.returnValue(false);
      const guard = roleGuard('client');
      const result = TestBed.runInInjectionContext(() =>
        guard({} as ActivatedRouteSnapshot, {} as RouterStateSnapshot)
      );
      expect(result).toBeFalse();
      expect(routerSpy.navigate).toHaveBeenCalledWith(['/login']);
    });
  });
});
"}

